1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - empty and single-item base premiums", () => {
6	    it("empty item list yields premium of 5G (processing fee only)", () => {
7	      expect(quote({ items: [], years: 0, priorContract: false })).toEqual({ premium: 5 });
8	    });
9	    it("single sword (no modifiers, 0 years, no prior contract) yields 100G base + 10G first insurance + 5G fee = 115G", () => {
10	      expect(quote({ items: [{ type: "sword" }], years: 0, priorContract: false })).toEqual({ premium: 115 });
11	    });
12	    it("single amulet yields 60G base + 10G first insurance + 5G fee = 75G", () => {
13	      expect(quote({ items: [{ type: "amulet" }], years: 0, priorContract: false })).toEqual({ premium: 75 });
14	    });
15	    it("single staff yields 80G base + 10G first insurance + 5G fee = 95G", () => {
16	      expect(quote({ items: [{ type: "staff" }], years: 0, priorContract: false })).toEqual({ premium: 95 });
17	    });
18	    it("single potion yields 40G base + 10G first insurance + 5G fee = 55G", () => {
19	      expect(quote({ items: [{ type: "potion" }], years: 0, priorContract: false })).toEqual({ premium: 55 });
20	    });
21	  });
22	
23	  describe("quote - components and building blocks", () => {
24	    it("single rune yields 25G base premium", () => {
25	      expect(quote({ items: [{ type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 40 });
26	    });
27	    it.todo("2 runes yields 50G base premium (no block)");
28	    it.todo("3 runes yields 60G base premium (block applies)");
29	    it.todo("4 runes yields 100G base premium (no block — block requires exactly 3)");
30	    it.todo("7 runes yields 175G base premium");
31	    it.todo("2 runes + 1 moonstone yields 75G base premium (no block: different types)");
32	    it.todo("3 runes + 3 moonstones yields 120G base premium (two separate blocks)");
33	  });
34	
35	  describe("quote - per-item modifiers", () => {
36	    it.todo("cursed sword adds 50G curse surcharge (50% of sword's 100G base)");
37	    it.todo("sword with enchantment exactly 5 adds 30G high-enchantment surcharge");
38	    it.todo("sword with enchantment 4 has no high-enchantment surcharge");
39	    it.todo("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
40	    it.todo("first insurance surcharge applies per item (each item in a quote is a first insurance)");
41	  });
42	
43	  describe("quote - policy-wide modifiers", () => {
44	    it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base premium");
45	    it.todo("follow-up contract (second quote in scenario) applies 15% discount on policy base premium");
46	    it.todo("processing fee of 5G is added at the very end after all modifiers");
47	  });
48	
49	  describe("quote - modifier scope on multi-item policies", () => {
50	    it.todo("cursed sword + plain amulet: curse adds 50G (50% of cursed sword's base), not of policy total → 210G before fee/loyalty/etc");
51	  });
52	
53	  describe("quote - rounding", () => {
54	    it.todo("premium of 197.5G rounds UP to 198G (in MHPCO's favor)");
55	  });
56	
57	  describe("quote - integration examples from spec", () => {
58	    it.todo("newcomer (0 years, no prior contract) with cursed sword (steel, enchantment 3) → 165G");
59	    it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → 160G");
60	  });
61	
62	  describe("claim - basic payouts and deductible", () => {
63	    it.todo("regular sword (steel, enchantment 3), damage 500G → payout 400G (full minus 100G deductible)");
64	    it.todo("damage to a rune (insurance value 250G), damage 200G → payout 100G (full minus 100G deductible)");
65	    it.todo("deductible applies once per damaged item (dragon attack: sword 500G + amulet 300G → payout 600G)");
66	  });
67	
68	  describe("claim - special clauses", () => {
69	    it.todo("sword with enchantment ≥ 8 reimburses 50% of damage (then deductible)");
70	    it.todo("dragon-material sword fully reimbursed (then deductible)");
71	    it.todo("dragon-material sword, enchantment 9, damage 1000G → payout 400G (50% rule wins, then deductible)");
72	    it.todo("dragon-material sword, enchantment 5, damage 800G → payout 700G (only dragon clause)");
73	    it.todo("steel sword, enchantment 9, damage 1000G → payout 400G (only high-enchantment clause)");
74	    it.todo("dragon-material sword, enchantment exactly 8, damage 1000G → payout 400G (high-enchantment clause applies, then deductible)");
75	  });
76	
77	  describe("claim - payout cap (2x insurance sum, cumulative)", () => {
78	    it.todo("policy covering sword has cap 2000G (2 × 1000G insurance value)");
79	    it.todo("cursed sword cap is 2000G — premium modifiers do not raise cap (based on unmodified insurance value)");
80	    it.todo("policy covers sword + 3 runes: insurance sum 1750G (block discount affects premium only, not insurance sum)");
81	    it.todo("two successive 1500G claims on a sword (cap 2000G): first payout 1400G (cap remaining 600G); second payout 600G (cap remaining 0G)");
82	  });
83	
84	  describe("claim - rounding", () => {
85	    it.todo("payout of 350.5G rounds DOWN to 350G (in MHPCO's favor)");
86	  });
87	
88	  describe("claim - multiple items of the same type", () => {
89	    it.todo("policy covers two swords: insurance sum 2000G, cap 4000G");
90	    it.todo("damages array with two sword entries on a 2-sword policy: each entry treated as separate damage with own deductible");
91	  });
92	
93	  describe("CLI - scenario processing", () => {
94	    it.todo("CLI reads JSON scenario from stdin and writes results array to stdout in same order as steps");
95	    it.todo("claim step references earlier quote via zero-based step index in policy field");
96	    it.todo("quote result contains integer premium field");
97	    it.todo("claim result contains integer payout and remainingCap fields");
98	  });
99	
100	  describe("CLI - error cases", () => {
101	    it.todo("quote with unknown item type (e.g. broomstick) → non-zero exit, error to stderr, no results to stdout");
102	    it.todo("claim referencing damage on item not in policy → non-zero exit, error to stderr");
103	    it.todo("claim referencing damage on item with unknown type → non-zero exit, error to stderr");
104	    it.todo("claim with negative damage amount → non-zero exit, error to stderr");
105	    it.todo("claim with more damage entries of a type than policy covers (e.g. two sword damages, one sword insured) → non-zero exit, whole claim rejected");
106	  });
107	});
